```hcl
# Variables
variable "aws_region" {
  description = "Région AWS"
  default     = "eu-west-3" # Paris
}

variable "bucket_name" {
  description = "Nom unique du bucket S3"
  type        = string
}

# Provider
provider "aws" {
  region = var.aws_region
}

# Ressource S3
resource "aws_s3_bucket" "student_bucket" {
  bucket = var.bucket_name
  acl    = "private"
  tags = {
    Name        = "Formation DevOps"
    Environment = "Training"
  }
}

# Ressource EC2
resource "aws_instance" "student_server" {
  ami           = "ami-0c55b159cbfafe1f0" # Amazon Linux 2 (us-east-1)
  instance_type = "t2.micro"
  tags = {
    Name = "Student-DevOps-Server"
  }
}
```

Commande pour visualiser les changements :
```bash
terraform plan
```
Cela montre les ajouts, modifications ou suppressions sans les appliquer.

**Coût actuel** :
10 instances * 0.0928 $/h * 24h * 30j = 10 * 0.0928 * 720 = 668,16 $/mois.

**Optimisation proposée** :
- Prix spot t2.micro = 0,004 $/h (économies ~95%).
- Moyenne 5 instances actives sur 24h.
Nouveau coût = 5 * 0.004 * 720 = 14,40 $/mois.

**Code Terraform (extrait)** :
```hcl
resource "aws_autoscaling_group" "optimized" {
  desired_capacity     = 5
  max_size             = 10
  min_size             = 2
  vpc_zone_identifier  = ["subnet-abc123"]

  mixed_instances_policy {
    instances_distribution {
      on_demand_percentage_above_base_capacity = 0 # 100% spot
    }
    launch_template {
      launch_template_specification {
        launch_template_id = aws_launch_template.app.id
      }
    }
  }
}

resource "aws_autoscaling_schedule" "night" {
  scheduled_action_name  = "reduce-at-night"
  min_size               = 2
  max_size               = 5
  desired_capacity       = 3
  recurrence             = "0 22 * * *"  # 22h chaque jour
}

resource "aws_autoscaling_schedule" "day" {
  scheduled_action_name  = "increase-day"
  min_size               = 5
  max_size               = 10
  desired_capacity       = 8
  recurrence             = "0 8 * * *"   # 8h chaque jour
}
```
**Économie** = 668,16 - 14,40 = 653,76 $/mois (réduction de 98%).
